sPitch_ps_spec/PeakAmp1', 'FRM_1/DesPitch_ps_spec/PeakFreq1', 'FRM_1/DesPitch_ps_spec/BandPower', 'FRM_1/Pitch_ps_spec/PeakAmp1', 'FRM_1/Pitch_ps_spec/PeakFreq1', 'FRM_1/Pitch_ps_spec/BandPower', 'FRM_1/DesYaw_ps_spec/BandPower', 'FRM_1/Yaw_ps_spec/BandPower', 'FRM_1/RPM0_ps_spec/BandPower', 'FRM_1/Curr0_ps_spec/BandPower', 'FRM_1/RPM1_ps_spec/BandPower', 'FRM_1/Curr1_ps_spec/BandPower', 'FRM_1/RPM2_ps_spec/BandPower', 'FRM_1/Curr2_ps_spec/BandPower', 'FRM_1/RPM3_ps_spec/BandPower', 'FRM_1/Curr3_ps_spec/BandPower', 'FRM_1/RPM4_ps_spec/BandPower', 'FRM_1/Curr4_ps_spec/BandPower', 'FRM_1/RPM5_ps_spec/BandPower', 'FRM_1/Curr5_ps_spec/BandPower', 'FRM_1/CTRL0_ps_spec/BandPower', 'FRM_1/CTRL1_ps_spec/BandPower', 'FRM_1/CTRL2_ps_spec/PeakAmp1', 'FRM_1/CTRL2_ps_spec/PeakFreq1', 'FRM_1/CTRL2_ps_spec/BandPower', 'FRM_1/CTRL3_ps_spec/PeakAmp1', 'FRM_1/CTRL3_ps_spec/PeakFreq1', 'FRM_1/CTRL3_ps_spec/BandPower', 'FRM_1/CTRL4_ps_spec/BandPower', 'FRM_1/CTRL5_ps_spec/BandPower'};
predictors = inputTable(:, predictorNames);
response = inputTable.WearPercentage;
isCategoricalPredictor = [false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, false, 